import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import MovieCard from '../components/MovieCard';
import { moviesAPI } from '../utils/api';
import '../styles/Movies.css';

const Movies = () => {
  const [movies, setMovies] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [filter, setFilter] = useState('all');
  const [searchQuery, setSearchQuery] = useState('');
  
  // Состояние для кастомного выпадающего списка
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  const statuses = [
    { value: 'all', label: 'All Movies' },
    { value: 'watched', label: 'Watched' },
    { value: 'watching', label: 'Watching' },
    { value: 'plan to watch', label: 'Plan to Watch' }
  ];

  useEffect(() => {
    fetchMovies();
    
    // Закрытие дропдауна при клике вне его
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const fetchMovies = async () => {
    try {
      const response = await moviesAPI.getAll();
      setMovies(response.data);
      setError('');
    } catch (error) {
      setError('Failed to load movies');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = (movieId) => {
    setMovies(movies.filter(movie => movie._id !== movieId));
  };

  const handleStatusSelect = (statusValue) => {
    setFilter(statusValue);
    setIsDropdownOpen(false);
  };

  const filteredMovies = movies
    .filter(movie => filter === 'all' || movie.status === filter)
    .filter(movie => movie.title.toLowerCase().includes(searchQuery.toLowerCase()));

  const stats = {
    total: movies.length,
    watched: movies.filter(m => m.status === 'watched').length,
    watching: movies.filter(m => m.status === 'watching').length,
    plan: movies.filter(m => m.status === 'plan to watch').length
  };

  if (loading) return <div className="loading">Loading...</div>;

  return (
    <div className="movies-page">
      <div className="movies-container">
        <div className="movies-header">
          <h1>My <span className="highlight">Movie Watchlist</span></h1>

          {/* Статистика */}
          <div className="stats-container">
            {Object.entries(stats).map(([key, val]) => (
              <div className="stat-card" key={key}>
                <div className="stat-value">{val}</div>
                <div className="stat-label"><h3>{key === 'plan' ? 'Plan' : key.charAt(0).toUpperCase() + key.slice(1)}</h3></div>
              </div>
            ))}
          </div>

          {/* БЕЛЫЙ КОНТЕЙНЕР ДЛЯ ПОИСКА (с эффектом свечения) */}
          <div className="search-filter-wrapper">
            <div className="search-filter-container">
              
              {/* Инпут поиска */}
              <div className="input-box">
                <input
                  type="text"
                  placeholder="Search by title..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />
                <i className='bx bx-search'></i>
              </div>

              {/* КАСТОМНЫЙ СЕЛЕКТ (как в MovieForm) */}
              <div className="input-box custom-select-container" ref={dropdownRef}>
                <div 
                  className={`custom-select ${filter !== 'all' ? 'selected' : ''}`} 
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                >
                  {statuses.find(s => s.value === filter)?.label}
                </div>
                <i className={`bx ${isDropdownOpen ? 'bx-chevron-up' : 'bx-chevron-down'}`}></i>
                
                {isDropdownOpen && (
                  <ul className="select-dropdown">
                    {statuses.map((s) => (
                      <li key={s.value} onClick={() => handleStatusSelect(s.value)}>
                        {s.label}
                      </li>
                    ))}
                  </ul>
                )}
              </div>

            </div>
          </div>
        </div>

        {/* Сетка фильмов */}
        <div className="movies-grid">
          {filteredMovies.map(movie => (
            <MovieCard key={movie._id} movie={movie} onDelete={handleDelete} />
          ))}
        </div>
      </div>
    </div>
  );
};

export default Movies;
